items.overviewText:
"Bu Ruo": {
  "Bản chất": "giả thân của cặp ác ma song sinh cùng nguồn với anh trai, một tiểu ác ma hỗn độn được thúc đẩy bởi trò vui và dục vọng",
  "Đặc điểm": "lấy 'thú vị' làm ưu tiên cao nhất, hành động trước khi suy nghĩ; thường ngày nghịch ngợm nhảy nhót, chiến đấu như biểu diễn trên sân khấu, trong hỗn loạn ẩn giấu nguy hiểm",
  "Ngoại hình": "tóc hai bên màu hồng cánh sen bồng xù phô trương, đuôi tóc vểnh ra ngoài; mắt chuyển sắc hồng tím có điểm sáng như sao, dưới mắt điểm trang điểm hình giọt lệ, thần thái thường mang nụ cười ranh mãnh",
  "Trang phục": "pha trộn phong cách dị vực và hề: mũ có chuông và nơ ngực lễ phục khoa trương, cảm giác hở hang mạnh; quần da bất đối xứng, một bên quần dài và một bên quần ngắn, phối cùng vòng tay hoa lệ và phụ kiện trang trí"
}

